const filePath = $input.first().json.filePath || '';
const fileExtension = filePath.split('.').pop().toLowerCase();
const textFileTypes = ['org', 'md', 'markdown', 'txt', 'html', 'xml', 'appleplist', 'asm', 'asp', 'batch', 'c', 'cs', 'css', 'csv', 'eml', 'go', 'ini', 'internetshortcut', 'java', 'javascript', 'json', 'latex', 'lisp', 'makefile', 'mht', 'mum', 'pem', 'perl', 'php', 'powershell', 'python', 'rdf', 'rst', 'rtf', 'ruby', 'rust', 'scala', 'shell', 'smali', 'sql', 'svg', 'symlinktext', 'vba', 'winregistry', 'yaml'];
const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];
const validFileTypes = textFileTypes.concat(binaryFileTypes);

return {
  isValid: validFileTypes.includes(fileExtension),
  fileExtension: fileExtension,
  encoding: binaryFileTypes.includes(fileExtension) ? 'binary' : 'utf8'
};

const filePath = $input.first().json.filePath || '';
const fileExtension = filePath.split('.').pop().toLowerCase();
const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];

let mimeType = 'text/plain';
switch (fileExtension) {
  case 'pdf':
    mimeType = 'application/pdf';
    break;
  case 'png':
    mimeType = 'image/png';
    break;
  case 'jpg':
  case 'jpeg':
    mimeType = 'image/jpeg';
    break;
  case 'webp':
    mimeType = 'image/webp';
    break;
  case 'md':
  case 'markdown':
    mimeType = 'text/markdown';
    break;
  case 'org':
    mimeType = 'text/org';
    break;
}

const encoding = binaryFileTypes.includes(fileExtension) ? 'binary' : 'utf8';
if (encoding === 'utf8') {
  mimeType += '; charset=UTF-8';
}

return {
  mimeType: mimeType,
  encoding: encoding,
  filePath: filePath
};

const files = $input.first().json.files || [];
const lastSync = $input.first().json.lastSync || [];
const filesToSync = [];

for (const file of files) {
  const lastSyncEntry = lastSync.find(f => f.path === file.path);
  if (!lastSyncEntry || new Date(file.mtime) > new Date(lastSyncEntry.datetime)) {
    filesToSync.push(file);
  }
}

return {
  filesToSync: filesToSync,
  totalFiles: filesToSync.length
};

const syncResponse = $input.first().json;
const filesToSync = $input.first().json.filesToSync || [];
const currentTime = new Date().toISOString();

const lastSync = filesToSync
  .filter(file => syncResponse.includes(file.path))
  .map(file => ({
    path: file.path,
    datetime: currentTime
  }));

return {
  success: true,
  lastSync: lastSync,
  syncTime: currentTime,
  filesCount: lastSync.length
};

const error = $input.first().json.error || {};
const statusCode = error.response?.status;
const message = error.message || 'Unknown error';

let errorMessage = '';

if (statusCode === 429) {
  errorMessage = 'Out of space. Upgrade your plan to unlock more space.';
} else if (error.code === 'ECONNREFUSED') {
  errorMessage = `Could not connect to Khoj server at ${error.address}:${error.port}`;
} else {
  errorMessage = `Sync failed: ${message}`;
}

return {
  success: false,
  error: errorMessage,
  statusCode: statusCode
};

const files = $input.first().json.files || [];
const folders = $input.first().json.folders || [];
const fileExtension = (path) => path.split('.').pop().toLowerCase();
const textFileTypes = ['org', 'md', 'markdown', 'txt', 'html', 'xml', 'appleplist', 'asm', 'asp', 'batch', 'c', 'cs', 'css', 'csv', 'eml', 'go', 'ini', 'internetshortcut', 'java', 'javascript', 'json', 'latex', 'lisp', 'makefile', 'mht', 'mum', 'pem', 'perl', 'php', 'powershell', 'python', 'rdf', 'rst', 'rtf', 'ruby', 'rust', 'scala', 'shell', 'smali', 'sql', 'svg', 'symlinktext', 'vba', 'winregistry', 'yaml'];
const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];
const validFileTypes = textFileTypes.concat(binaryFileTypes);
const isSupportedFileType = (filePath) => validFileTypes.includes(fileExtension(filePath));

const filesToIndex = [];

for (const file of files) {
  if (isSupportedFileType(file.path)) {
    filesToIndex.push(file.path);
  }
}

for (const folder of folders) {
  // Placeholder for recursive directory processing
  filesToIndex.push(folder.path);
}

return {
  filesToIndex: filesToIndex,
  totalFiles: filesToIndex.length
};
